import{_ as a}from"./chunks/afdian.BUdhV4x0.js";import{p as r,bh as s,I as i,U as e,A as t}from"./chunks/framework.BpabEsSf.js";const b=JSON.parse('{"title":"プロジェクト紹介","description":"","frontmatter":{"title":"プロジェクト紹介","date":"2026-05-01T23:30:00.000Z","permalink":"/guide/intro","categories":["プロジェクト紹介"],"tags":["プロジェクト"]},"headers":[],"relativePath":"ja/01.Guide/01.Introduction/01.Project Introduction.md","filePath":"ja/01.Guide/01.Introduction/01.Project Introduction.md","lastUpdated":null}'),n={name:"ja/01.Guide/01.Introduction/01.Project Introduction.md"};function d(c,o,l,g,h,p){return s(),i("div",null,[...o[0]||(o[0]=[e('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /ja\\01.Guide\\01.Introduction\\01.Project Introduction.md for this page in Markdown format</div><h1 id="プロジェクト紹介" tabindex="-1">プロジェクト紹介 <a class="header-anchor" href="#プロジェクト紹介" aria-label="Permalink to &quot;プロジェクト紹介&quot;">​</a></h1><h1 align="center">Monica ローカルパスワードマネージャー</h1><p align="center"><strong>Bitwarden と KeePass を統合したローカルファーストのパスワード管理ツール</strong></p><p align="center">Android / Browser · Local Vault · TOTP · WebDAV Backup</p>',5),t("div",{class:"container share-card-container"},[t("div",{class:"share-card index-auto",style:{"--row-gap":"20px","--column-gap":"20px","--column-min-width":"calc(100% / 4 - 60px)"}},[t("a",{href:"https://github.com/JoyinJoester",target:"_blank",class:"share-card__item row-4",style:{"--item-bg-color":"#FFB6C1","--item-text-color":"#621529"}},[t("div",{class:"share-card__item__img skeleton-image"},[t("img",{src:"https://avatars.githubusercontent.com/u/87232423",alt:"天才プログラマー JoyinJoester",class:"no-preview",onload:"this.classList.add('loaded')",onerror:"this.classList.add('loaded')"})]),t("div",{class:"share-card__item__content"},[t("p",{class:"name"},"天才プログラマー JoyinJoester"),t("p",{class:"desc"},"彼（彼女）の伝説的な開発ストーリーをご紹介します。")])]),t("a",{href:"https://afdian.com/a/JoyinJoester",target:"_blank",class:"share-card__item row-4",style:{"--item-bg-color":"#FFEBF2","--item-text-color":"#621529"}},[t("div",{class:"share-card__item__img skeleton-image"},[t("img",{src:a,alt:"スポンサー・ご支援",class:"no-preview",onload:"this.classList.add('loaded')",onerror:"this.classList.add('loaded')"})]),t("div",{class:"share-card__item__content"},[t("p",{class:"name"},"スポンサー・ご支援"),t("p",{class:"desc"},"コーヒー1杯で、個人開発者のフルタイム活動を応援してください！")])])])],-1),t("div",{class:"container nav-card-container"},[t("div",{class:"nav-card index-auto",style:{"--row-gap":"20px","--column-gap":"20px","--column-min-width":"calc(100% / 4 - 60px)"}},[t("a",{href:"http://www.linux.do/",target:"_blank",class:"nav-card__item row-4",style:{"--desc-line-clamp":"2"}},[t("div",{class:"nav-card__item__info"},[t("div",{class:"nav-card__item__img skeleton-image"},[t("img",{src:"https://linux.do/logo-128.svg",class:"no-preview",onload:"this.classList.add('loaded')",onerror:"this.classList.add('loaded')"})]),t("span",{class:"name"},"Linux Do")]),t("p",{class:"desc"},"Lコミュニティ。チュートリアルやITニュースの記録・共有スペース。"),t("span",{class:"VPBadge tip badge"},"相互リンク")]),t("a",{href:"https://qm.qq.com/q/2vTdTkHV3u",target:"_blank",class:"nav-card__item row-4",style:{"--desc-line-clamp":"2"}},[t("div",{class:"nav-card__item__info"},[t("div",{class:"nav-card__item__img skeleton-image"},[t("img",{src:"https://p.qlogo.cn/gh/1087865010/1087865010/",class:"no-preview",onload:"this.classList.add('loaded')",onerror:"this.classList.add('loaded')"})]),t("span",{class:"name"},"QQ グループ")]),t("p",{class:"desc"},"QQ交流グループ（1087865010）に参加して、雑談やバグ報告、開発者との交流を楽しみましょう。"),t("span",{class:"VPBadge info badge"},"交流グループ")])])],-1),e('<div class="danger custom-block"><p class="custom-block-title">⚠️ 安全なバックアップに関する重要なお知らせ</p><p><strong>データのプライバシーは極めて貴重です！必ず定期的に複数のメディアへバックアップを作成してください！</strong></p><p>バックアップは必ず適切に作成してください。データのプライバシーに代わるものはありません！すべてのデータをこの一つのアプリだけに依存させず、リスクを分散させてください。</p></div><p><code>Monica</code> は、<strong>Bitwarden</strong> と <strong>KeePass</strong> のエコシステムを統合した、ローカルファーストのパスワード管理ツール（Local Vault）です。 ローカルストレージ優先を核とし、Android およびデスクトップブラウザ環境で、アカウント情報、パスワード、2FA（二段階認証）トークン、セキュアノート、機密添付ファイルを一元管理できます。</p><div class="info custom-block"><p class="custom-block-title">📌 プロジェクトの現状に関するお知らせ</p><ul><li><strong>Monica for Windows</strong> はアーカイブされました。過去のコードは <a href="https://github.com/JoyinJoester/Monica-for-Windows" target="_blank" rel="noreferrer"><code>Monica-for-Windows</code></a> をご覧ください。</li><li>⏳ 現在の開発リソースが限られているため、<code>Monica for Wear</code> および <code>Monica for Browser</code> は一時的に<strong>継続的なアップデートを停止</strong>しています。</li><li>🎯 現段階では、<strong><code>Monica for Android</code></strong> の機能充実、UI/UXの最適化、および安定性の維持に全力を注いでいます。ご理解のほどよろしくお願いいたします。</li></ul></div><h2 id="🧭-ユーザーガイド" tabindex="-1">🧭 ユーザーガイド <a class="header-anchor" href="#🧭-ユーザーガイド" aria-label="Permalink to &quot;🧭 ユーザーガイド&quot;">​</a></h2><h3 id="🎯-monica-はどのような人向けか" tabindex="-1">🎯 Monica はどのような人向けか <a class="header-anchor" href="#🎯-monica-はどのような人向けか" aria-label="Permalink to &quot;🎯 Monica はどのような人向けか&quot;">​</a></h3><ul><li class="todo"><input class="todo-checkbox" type="checkbox" checked disabled><strong>ローカル優先</strong>の認証情報管理を求め、サードパーティのクラウドサーバーに機密データを預けたくないユーザー。</li><li class="todo"><input class="todo-checkbox" type="checkbox" checked disabled><strong>Bitwarden</strong> のエコシステムを使いつつ、同時に <strong>KeePass</strong>（<code>.kdbx</code>）のデータも維持しているデュアル環境のユーザー。</li><li class="todo"><input class="todo-checkbox" type="checkbox" checked disabled>Android 端末で日常的に効率よく使用し、同時にブラウザ側で<strong>インテリジェントな自動入力</strong>を行いたい方。</li></ul><h3 id="🎁-利用できる機能" tabindex="-1">🎁 利用できる機能 <a class="header-anchor" href="#🎁-利用できる機能" aria-label="Permalink to &quot;🎁 利用できる機能&quot;">​</a></h3><ul><li><strong>ローカル暗号化金庫</strong>: ログイン情報、クレジットカード、身分証明書、セキュアノート、添付ファイルを安全に保護します。</li><li><strong>2つのエコシステムの統合</strong>: Android 側で Bitwarden API との同期能力を備えつつ、KeePass（<code>.kdbx</code>）のネイティブな読み書きにも対応しています。</li><li><strong>多様な同期・バックアップ</strong>: 自前で構築した WebDAV インフラを介して、デバイス間でデータを安全に連携・流転させることができます。</li><li><strong>TOTP 内蔵</strong>: パスワード管理と同時に、二段階認証（2FA）コードの生成・管理を単一のアプリ内で完結できます。</li></ul><h2 id="📱-android-版のハイライト" tabindex="-1">📱 Android 版のハイライト <a class="header-anchor" href="#📱-android-版のハイライト" aria-label="Permalink to &quot;📱 Android 版のハイライト&quot;">​</a></h2><h3 id="✨-コア機能" tabindex="-1">✨ コア機能 <a class="header-anchor" href="#✨-コア機能" aria-label="Permalink to &quot;✨ コア機能&quot;">​</a></h3><ul><li><strong>ローカル Vault</strong> — すべてのコア認証情報は、ローカル環境で高強度の暗号化アルゴリズムを用いて安全に保存されます。</li><li><strong>統合インポート</strong> — KeePass データからのスムーズな移行と、Bitwarden エコシステムとの柔軟な互換接続を完全サポートします。</li><li><strong>スマート検索</strong> — タイトル、ドメイン名、カスタムタグなど、多次元的なクエリから目的の認証情報を素早く特定できます。</li><li><strong>生体認証</strong> — システム標準の生体認証（指紋/顔認証）と連動し、確固たるセキュリティと即座の起動を両立します。</li><li><strong>TOTP 管理</strong> — 二段階認証用のワンタイムパスワードを統合管理し、動的に生成します。</li></ul><h3 id="🛠️-技術スタック" tabindex="-1">🛠️ 技術スタック <a class="header-anchor" href="#🛠️-技術スタック" aria-label="Permalink to &quot;🛠️ 技術スタック&quot;">​</a></h3><p>本プロジェクトのアーキテクチャおよび選型は、Android の現代的な開発手法（Modern Android Development - MAD）に厳格に準拠しています：</p><table tabindex="0"><thead><tr><th>レイヤー</th><th>採用技術およびコンポーネント</th></tr></thead><tbody><tr><td><strong>UI プレゼンテーション層</strong></td><td><code>Jetpack Compose</code> + <code>Material 3</code> + <code>Navigation Compose</code></td></tr><tr><td><strong>データ永続化層</strong></td><td><code>Room</code> (<code>PasswordDatabase</code>) + データアクセスオブジェクト (DAO) + リポジトリパターン</td></tr><tr><td><strong>非同期・並行処理モデル</strong></td><td>Kotlin <code>Coroutines</code>（コルーチン） + <code>Flow</code> 反応型データストリーム</td></tr><tr><td><strong>依存関係注入 (DI)</strong></td><td><code>Koin</code>（アプリ起動時に <code>MonicaApplication</code> 内で高凝集に初期化設定）</td></tr><tr><td><strong>バックグラウンドタスク</strong></td><td><code>WorkManager</code>（<code>AutoBackupWorker</code> により、軽量かつ堅牢な自動 WebDAV バックアップを実現）</td></tr><tr><td><strong>下位プロトコルと外部連携</strong></td><td><code>Retrofit</code> + <code>OkHttp</code> (Bitwarden API)<br></td></tr></tbody></table><p><br><code>kotpass</code> (KeePass コア解析エンジン)<br></p><p><br><code>sardine-android</code> (WebDAV クライアント) |</p><h3 id="🔒-純粋なセキュリティモデル" tabindex="-1">🔒 純粋なセキュリティモデル <a class="header-anchor" href="#🔒-純粋なセキュリティモデル" aria-label="Permalink to &quot;🔒 純粋なセキュリティモデル&quot;">​</a></h3><p>パスワードマネージャーの根幹はセキュリティにあります。Monica は下位レイヤーにおいて厳格な防衛アーキテクチャを設計しています：</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>1. コア暗号化アルゴリズム</strong><strong><code>AES-256-GCM</code></strong> 認証暗号化アルゴリズムを採用。データの機密性を保証するだけでなく、包括的な整合性検証を提供し、データの改ざんを防御します。</p></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>2. 鍵派生メカニズム</strong><strong><code>PBKDF2-HMAC-SHA256</code></strong> アルゴリズムを導入し、非常に高い反復（イテレーション）パラメータを設定。これにより、オフラインでの総当たり攻撃やレインボーテーブル攻撃の技術的・時間的コストを劇的に引き上げます。</p></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>3. ハードウェア級のローカル保護</strong> ユーザーのマスターパスワードのハッシュ値およびコアセキュリティ設定は、Android システムレベルの安全コンポーネントである <strong><code>Android Keystore</code></strong>、<strong><code>EncryptedSharedPreferences</code></strong>、および <strong><code>BiometricPrompt</code></strong> が共同で管理します。暗号化鍵がハードウェアの安全区域から外に出ることはありません。</p></div><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p><strong>4. 明確なネットワーク境界</strong> アプリが宣言しているネットワーク権限は、Bitwarden API との連携、ユーザーが自発的に実行する WebDAV バックアップおよび同期といったオンライン機能に<strong>のみ、厳格に</strong>限定されています。サードパーティによるトラッカーや埋め込み、未知のデータアップロードは一切存在しません。</p></div><h2 id="🤝-オープンソースへの謝辞" tabindex="-1">🤝 オープンソースへの謝辞 <a class="header-anchor" href="#🤝-オープンソースへの謝辞" aria-label="Permalink to &quot;🤝 オープンソースへの謝辞&quot;">​</a></h2><p><code>Monica</code> の設計、互換性の最適化、および一部の機能方針は、オープンソースコミュニティから深い恩恵を受けています。以下の優れたオープンソースプロジェクトとソフトウェアのインスピレーションおよびサポートに、心より感謝申し上げます：</p><ul><li><strong><a href="https://github.com/AChep/keyguard-app" target="_blank" rel="noreferrer">Keyguard</a></strong> — Android パスワードマネージャーにおける優れたインタラクションデザインとユーザー体験の参考にさせていただきました。</li><li><strong><a href="https://bitwarden.com/" target="_blank" rel="noreferrer">Bitwarden</a></strong> — オープンソースのパスワード管理エコシステム、データスキーマ、複数クライアント間の同期能力の重要なリファレンスです。</li><li><strong><a href="https://keepass.info/" target="_blank" rel="noreferrer">KeePass</a></strong> — 伝統的なローカルパスワード管理の理念であり、本アプリにおける <code>.kdbx</code> ファイルの互換性と読み書きの基礎となっています。</li><li><strong><a href="https://github.com/stratumauth/app" target="_blank" rel="noreferrer">Stratum Auth</a></strong> — 認証器（2FA）の操作体験、高品質なブランドアイコンパッケージ、および関連する互換仕様の参考にさせていただきました。</li></ul><h2 id="📈-star-history" tabindex="-1">📈 Star History <a class="header-anchor" href="#📈-star-history" aria-label="Permalink to &quot;📈 Star History&quot;">​</a></h2><div class="center tk-center-container"><p>下のチャートをクリックすると、プロジェクトの全スター履歴ダッシュボードへ遷移できます。</p></div><p><a href="https://star-history.com/#JoyinJoester/Monica&amp;Date" target="_blank" rel="noreferrer"><img src="https://api.star-history.com/svg?repos=JoyinJoester/Monica&amp;type=Date" alt="Star History Chart" loading="lazy"></a></p><h2 id="📑-ライセンスと資産表記" tabindex="-1">📑 ライセンスと資産表記 <a class="header-anchor" href="#📑-ライセンスと資産表記" aria-label="Permalink to &quot;📑 ライセンスと資産表記&quot;">​</a></h2><div class="note custom-block"><p class="title note-title custom-block-title">ライセンス宣言</p><p>Copyright (c) 2025 JoyinJoester</p><p>本プロジェクトは、<strong><a href="https://www.google.com/search?q=LICENSE" target="_blank" rel="noreferrer">GNU General Public License v3.0</a></strong> に基づいて厳格に公開されています。ライセンスの規定に従う限り、ソフトウェアの配布、修正、および二次開発が認められます。</p></div><h2 id="📦-サードパーティ製アイコンおよび商標に関する注記" tabindex="-1">📦 サードパーティ製アイコンおよび商標に関する注記 <a class="header-anchor" href="#📦-サードパーティ製アイコンおよび商標に関する注記" aria-label="Permalink to &quot;📦 サードパーティ製アイコンおよび商標に関する注記&quot;">​</a></h2><p>より直感的な認証器管理体験を提供するため、本プロジェクトでは一部のサードパーティ製静的資産をローカルにパッケージ化して引用しています：</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><ol><li><strong>アイコンリソースの引用</strong>: 本プロジェクトには、<a href="https://github.com/stratumauth/app" target="_blank" rel="noreferrer">Stratum Auth app</a> から提供されたアイコンリソース（バージョン <code>v1.4.0</code>、<code>icons</code> および <code>extraicons</code> ディレクトリを含む）がローカルに同梱されています。これらの資産も同様に GPL-3.0 ライセンス下で公開されています。原作者の無私な貢献に感謝いたします。</li><li><strong>商標に関するガイドライン</strong>: ドキュメントおよびアプリケーション内で言及されているすべてのサードパーティのブランド名、登録商標、および商業ロゴは、それぞれの法的な権利所有者に帰属します。</li></ol></div>',33)])])}const _=r(n,[["render",d]]);export{b as __pageData,_ as default};
